const inputItems = $input.all();
const firstJson = inputItems[0]?.json || {};
const pages = Array.isArray(firstJson.results) ? firstJson.results : inputItems.map((item) => item.json);
function readPlainText(prop) {
  if (!prop) return '';
  if (prop.title) return prop.title.map((t) => t.plain_text || t.text?.content || '').join('');
  if (prop.rich_text) return prop.rich_text.map((t) => t.plain_text || t.text?.content || '').join('');
  return '';
}
function firstTitle(properties) {
  for (const value of Object.values(properties || {})) {
    if (value?.type === 'title' || value?.title) return readPlainText(value);
  }
  return '';
}
return pages.map((page) => {
  const properties = page.properties || {};
  const clientName = firstTitle(properties) || page.id;
  return { json: { clientPageId: page.id, clientName, clientProperties: properties, projectQueryPayload: { page_size: 1, filter: { and: [{ property: 'Cliente', relation: { contains: page.id } }, { property: 'Tipo de Projeto', select: { equals: 'Configura\u00e7\u00e3o/Setup' } }] } } } };
});

const existing = $json.results || [];
if (existing.length > 0) return [];
const client = $('Expand Active Clients').item.json;
const props = client.clientProperties || {};
function propValue(prop) {
  if (!prop) return null;
  if (prop.title) return prop.title.map((t) => t.plain_text || t.text?.content || '').join('');
  if (prop.rich_text) return prop.rich_text.map((t) => t.plain_text || t.text?.content || '').join('');
  if (prop.number !== undefined) return prop.number;
  if (prop.select) return prop.select.name;
  if (prop.status) return prop.status.name;
  if (prop.email) return prop.email;
  if (prop.phone_number) return prop.phone_number;
  if (prop.url) return prop.url;
  if (prop.formula) return prop.formula.string ?? prop.formula.number ?? prop.formula.boolean ?? prop.formula.date?.start ?? null;
  if (prop.rollup) return prop.rollup.number ?? prop.rollup.array ?? prop.rollup.date?.start ?? null;
  if (prop.relation) return prop.relation.length;
  if (prop.multi_select) return prop.multi_select.length;
  if (prop.date) return prop.date.start;
  if (prop.checkbox !== undefined) return prop.checkbox;
  return null;
}
function filled(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') return value.trim() !== '' && value.trim() !== '0';
  if (Array.isArray(value)) return value.length > 0;
  return Boolean(value);
}
function escHtml(value) { return String(value).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'); }
const checks = [['Verificar ID Conta de An\u00fancio', 'ID Conta de An\u00fancio'], ['Verificar ID do Pixel (Meta)', 'ID do Pixel'], ['Verificar BM ID (Meta)', 'BM ID'], ['Verificar ID Propriedade Analytics', 'ID Prop Analytcs'], ['Verificar ID Perfil GBP', 'ID Perfil GBP'], ['Verificar Client ID - Google', 'Client ID - Google']].map(([itemName, fieldName]) => { const value = propValue(props[fieldName]); return { itemName, fieldName, filled: filled(value) }; });
const missing = checks.filter((check) => !check.filled).map((check) => check.fieldName);
const today = new Intl.DateTimeFormat('en-CA', { timeZone: 'America/Sao_Paulo', year: 'numeric', month: '2-digit', day: '2-digit' }).format(new Date());
const projectTitle = `[Setup] ${client.clientName} \u2014 Configura\u00e7\u00e3o de Contas`;
const telegramText = missing.length === 0 ? '' : `<b>Setup pendente</b>\nCliente: ${escHtml(client.clientName)}\n\n<b>Configura\u00e7\u00f5es faltando:</b>\n` + missing.map((name) => `- ${escHtml(name)}`).join('\n');
return { json: { clientPageId: client.clientPageId, clientName: client.clientName, checks, missing, telegramText, projectPayload: { properties: { Projeto: { title: [{ text: { content: projectTitle } }] }, 'Tipo de Projeto': { select: { name: 'Configura\u00e7\u00e3o/Setup' } }, Status: { status: { name: 'N\u00e3o Iniciado' } }, Cliente: { relation: [{ id: client.clientPageId }] }, 'Data de In\u00edcio': { date: { start: today } } } } } };

const projectPageId = $json.id;
const setup = $('Prepare Setup Payload').item.json;
return setup.checks.map((check) => ({ json: { checklistPayload: { parent: { database_id: '19fb65e5-c72b-8171-b535-000b978f7811' }, properties: { Nome: { title: [{ text: { content: check.itemName } }] }, Projeto: { relation: [{ id: projectPageId }] }, 'Criado por': { select: { name: 'n8n' } }, 'Conclu\u00eddo?': { checkbox: check.filled } } } } }));

const setup = $('Prepare Setup Payload').item.json;
if (!setup.missing || setup.missing.length === 0) return [];
return { json: { projectPageId: $json.id, missing: setup.missing, telegramText: setup.telegramText } };

const alert = $('Prepare Telegram Alert').item.json;
const timestamp = new Date().toISOString();
const missing = alert.missing || [];
return { json: { projectPageId: alert.projectPageId, logPayload: { children: [{ object: 'block', type: 'callout', callout: { icon: { type: 'emoji', emoji: '\u2699\ufe0f' }, rich_text: [{ type: 'text', text: { content: `Telegram: ok -- ${timestamp} -- faltando: [${missing.join(', ')}]` } }], color: 'yellow_background' } }] } } };

const alert = $('Prepare Telegram Alert').item.json;
const timestamp = new Date().toISOString();
const missing = alert.missing || [];
const errorMessage = $json.error?.message || $json.message || 'unknown error';
return { json: { projectPageId: alert.projectPageId, logPayload: { children: [{ object: 'block', type: 'callout', callout: { icon: { type: 'emoji', emoji: '\u26a0\ufe0f' }, rich_text: [{ type: 'text', text: { content: `Telegram: falhou -- ${timestamp} -- faltando: [${missing.join(', ')}] -- ${errorMessage}` } }], color: 'red_background' } }] } } };

const setup = $('Prepare Setup Payload').item.json;
if (setup.missing && setup.missing.length > 0) return [];
const timestamp = new Date().toISOString();
return { json: { projectPageId: $json.id, logPayload: { children: [{ object: 'block', type: 'callout', callout: { icon: { type: 'emoji', emoji: '\u2705' }, rich_text: [{ type: 'text', text: { content: `Sem alerta (nada faltando) -- ${timestamp}` } }], color: 'green_background' } }] } } };
